INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 11, "", 10, 13020023, "", 302, "", "ふむ…これは僥倖\nかくなる上は再び\n潜航してみるか…", "", 111031);
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 91, "", "", 13020024, "", 302, "", "", "", 0);
